<?php session_start(); require 'includes/header.php'; require_login();
if(isset($_GET['approve']) && can_approve()){ $id=(int)$_GET['approve']; $pdo->prepare("UPDATE stock_requests SET status='Approved',approved_qty=qty,approved_at=NOW() WHERE id=?")->execute([$id]); log_action($pdo,'Request approved','#'.$id); header('Location:requests.php'); exit; }
if(isset($_GET['reject']) && can_approve()){ $id=(int)$_GET['reject']; $pdo->prepare("UPDATE stock_requests SET status='Rejected',approved_at=NOW() WHERE id=?")->execute([$id]); log_action($pdo,'Request rejected','#'.$id); header('Location:requests.php'); exit; }
if(isset($_GET['issue']) && can_manage()){ $id=(int)$_GET['issue']; $r=$pdo->prepare('SELECT * FROM stock_requests WHERE id=?'); $r->execute([$id]); $rq=$r->fetch(); $bal=$pdo->query('SELECT current_stock FROM items WHERE id='.(int)$rq['item_id'])->fetch()['current_stock']; if($rq && $rq['status']=='Approved' && $bal >= $rq['approved_qty']){ $pdo->beginTransaction(); $pdo->prepare('INSERT INTO stock_out(item_id,qty,issue_date,department,issued_to,purpose,issued_by,request_id) VALUES(?,?,CURDATE(),?,?,?,?,?)')->execute([$rq['item_id'],$rq['approved_qty'],$rq['department'],'Requested Staff',$rq['purpose'],$_SESSION['user']['id'],$id]); $pdo->prepare('UPDATE items SET current_stock=current_stock-? WHERE id=?')->execute([$rq['approved_qty'],$rq['item_id']]); $pdo->prepare("UPDATE stock_requests SET status='Issued',issued_at=NOW() WHERE id=?")->execute([$id]); $pdo->commit(); } header('Location:requests.php'); exit; }
if($_SERVER['REQUEST_METHOD']==='POST'){ $pdo->prepare('INSERT INTO stock_requests(request_no,item_id,qty,requested_by,department,purpose) VALUES(?,?,?,?,?,?)')->execute([next_request_no($pdo),$_POST['item_id'],$_POST['qty'],$_SESSION['user']['id'],$_POST['department'],$_POST['purpose']]); log_action($pdo,'Request created',$_POST['purpose']); header('Location:requests.php'); exit; }
$items=$pdo->query('SELECT * FROM items ORDER BY name')->fetchAll(); $rows=$pdo->query('SELECT r.*,i.name item,u.full_name user FROM stock_requests r JOIN items i ON i.id=r.item_id JOIN users u ON u.id=r.requested_by ORDER BY r.id DESC')->fetchAll();
?><h1>Stock Requests</h1><div class="card"><form method="post" class="formgrid"><select name="item_id" required><option value="">Select Item</option><?php foreach($items as $i) echo '<option value="'.$i['id'].'">'.e($i['name']).'</option>'; ?></select><input name="qty" type="number" step="0.01" placeholder="Quantity" required><input name="department" placeholder="Department"><textarea name="purpose" placeholder="Purpose"></textarea><button>Submit Request</button></form></div><div class="card"><table><tr><th>No</th><th>Item</th><th>Qty</th><th>By</th><th>Status</th><th>Action</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['request_no'])?></td><td><?=e($r['item'])?></td><td><?=e($r['qty'])?></td><td><?=e($r['user'])?></td><td><span class="badge"><?=e($r['status'])?></span></td><td><?php if($r['status']=='Pending' && can_approve()): ?><a class="btn" href="?approve=<?=$r['id']?>">Approve</a> <a class="btn danger" href="?reject=<?=$r['id']?>">Reject</a><?php endif ?><?php if($r['status']=='Approved' && can_manage()): ?> <a class="btn" href="?issue=<?=$r['id']?>">Issue</a><?php endif ?></td></tr><?php endforeach ?></table></div><?php require 'includes/footer.php'; ?>
